import React, { useState } from "react";
import "./Gallery.css";

function Gallery({ cart, setCart }) {
  const artworks = [
    { title: "Peinture abstraite", size: "80x60 cm", price: 120, image: "/images/art1.jpg" },
    { title: "Sculpture moderne", size: "40x25x25 cm", price: 250, image: "/images/art2.jpg" },
    { title: "Dessin au fusain", size: "30x40 cm", price: 80, image: "/images/art3.jpg" },
    { title: "Collage coloré", size: "70x50 cm", price: 150, image: "/images/art4.jpg" },
  ];

  const [clickedButton, setClickedButton] = useState(null);
  const [toastMessage, setToastMessage] = useState("");

  const addToCart = (item, index) => {
    setCart([...cart, item]);

    // Effet bouton
    setClickedButton(index);
    setTimeout(() => setClickedButton(null), 500);

    // Affiche toast
    setToastMessage(`${item.title} ajouté au panier ✅`);
    setTimeout(() => setToastMessage(""), 2000); // disparaît après 2 sec
  };

  return (
    <div className="gallery-container">
      <h2>Galerie d'art</h2>

      {/* ✅ Toast message */}
      {toastMessage && <div className="toast">{toastMessage}</div>}

      <div className="gallery-grid">
        {artworks.map((item, index) => (
          <div key={index} className="art-card">
            <img src={item.image} alt={item.title} />
            <h3>{item.title}</h3>
            <p className="size">{item.size}</p>
            <p className="price">{item.price} €</p>
            <button
              onClick={() => addToCart(item, index)}
              className={clickedButton === index ? "added" : ""}
            >
              Ajouter au panier
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Gallery;
